func newShortcodeHandler(filename string, s *Site) *shortcodeHandler {
	sh := &shortcodeHandler{
		filename:		filename,
		s:			s,
		enableInlineShortcodes:	s.ExecHelper.Sec().EnableInlineShortcodes,
		shortcodes:		make([]*shortcode, 0, 4),
		nameSet:		make(map[string]bool),
	}

	return sh
}
